class ExamRoom {
    TreeSet<Integer> seats;
    int n;

    public ExamRoom(int n) {
        this.n = n;
        this.seats = new TreeSet<>();
    }

    public int seat() {
        if (seats.isEmpty()) {
            seats.add(0);
            return 0;
        }
        int ans = 0;
        int d = 0;
        int prev = -1;
        for (int s : seats) {
            if (prev != -1) {
                if (s - prev > d) {
                    d = s - prev;
                    ans = prev + d / 2;
                }
            } else {
                ans = 0;
                d = s;
            }
            prev = s;
        }
        if (n - 1 - prev > d) {
            ans = prev + (n - 1 - prev) / 2;
        }
        seats.add(ans);
        return ans;
    }

    public void leave(int p) {
        seats.remove(p);
    }
}
```
